INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('64537204-ede8-4be9-b3b2-bb1a6ffab1aa', $q$Multi-protocol API Gateway$q$, $q$A single gateway handles REST, GraphQL, gRPC, WebSocket and Kafka-based event traffic instead of requiring separate tools per protocol.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('64537204-ede8-4be9-b3b2-bb1a6ffab1aa', $q$Access Management$q$, $q$Built-in OAuth2 and OpenID Connect identity and access management for securing APIs and consumers.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('64537204-ede8-4be9-b3b2-bb1a6ffab1aa', $q$API Designer and Developer Portal$q$, $q$Tools for designing, mocking and publishing APIs to a self-service developer portal for internal and external consumers.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('64537204-ede8-4be9-b3b2-bb1a6ffab1aa', $q$Cockpit control plane$q$, $q$Centralized visibility and governance across multiple gateways, environments and teams.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('64537204-ede8-4be9-b3b2-bb1a6ffab1aa', $q$Alert Engine$q$, $q$Real-time alerting on gateway health, traffic anomalies and policy violations.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('64537204-ede8-4be9-b3b2-bb1a6ffab1aa', $q$Event broker mediation$q$, $q$Native support for Kafka and other event brokers so event-driven architectures get the same governance as REST APIs.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('64537204-ede8-4be9-b3b2-bb1a6ffab1aa', $q$AI agent and MCP management$q$, $q$An LLM proxy, MCP proxy and agent catalog that extend API-style governance, rate limiting and observability to AI agents and Model Context Protocol servers.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('64537204-ede8-4be9-b3b2-bb1a6ffab1aa', $q$Open-source Community Edition$q$, $q$A free, Apache 2.0 licensed self-hosted edition that includes the core gateway, portal and analytics.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('64537204-ede8-4be9-b3b2-bb1a6ffab1aa', $q$Free, actively maintained open-source Community Edition with no artificial feature caps on core gateway functionality$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('64537204-ede8-4be9-b3b2-bb1a6ffab1aa', $q$Unlimited API calls and events per gateway rather than metered usage pricing, which makes costs predictable at scale$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('64537204-ede8-4be9-b3b2-bb1a6ffab1aa', $q$Native support for both REST/GraphQL APIs and Kafka-style event streaming in one platform$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('64537204-ede8-4be9-b3b2-bb1a6ffab1aa', $q$Early, dedicated tooling for governing AI agents and MCP servers rather than bolting AI support onto a legacy product$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('64537204-ede8-4be9-b3b2-bb1a6ffab1aa', $q$Commercial tiers above the entry Planet plan require a custom quote, making upfront cost comparison difficult$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('64537204-ede8-4be9-b3b2-bb1a6ffab1aa', $q$Gateway-based pricing can get expensive quickly for organizations that need many production gateways for isolation$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('64537204-ede8-4be9-b3b2-bb1a6ffab1aa', $q$Smaller ecosystem and third-party plugin marketplace compared to larger incumbents like Kong or Apigee$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('64537204-ede8-4be9-b3b2-bb1a6ffab1aa', $q$Self-hosting the Community Edition requires in-house DevOps expertise for scaling and upgrades$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('64537204-ede8-4be9-b3b2-bb1a6ffab1aa', $q$Is Gravitee free to use$q$, $q$Yes. The Gravitee Community Edition is free and open source under an Apache 2.0 license and can be self-hosted, though it lacks the enterprise support, advanced plugins and managed hosting of the paid tiers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('64537204-ede8-4be9-b3b2-bb1a6ffab1aa', $q$What does Gravitee cost$q$, $q$Paid API Management plans start at Planet for 2,500 US dollars per month for one production gateway with unlimited users and API calls, with the Galaxy and Universe tiers priced individually based on gateway count and enterprise requirements.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('64537204-ede8-4be9-b3b2-bb1a6ffab1aa', $q$Does Gravitee support Kafka and event-driven architectures$q$, $q$Yes. Gravitee has a dedicated Event Management product line, starting at the Comet plan, that mediates Kafka and other event brokers with the same governance model used for REST APIs.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('64537204-ede8-4be9-b3b2-bb1a6ffab1aa', $q$Can Gravitee manage AI agents and MCP servers$q$, $q$Yes. Gravitee added an LLM proxy, an MCP proxy and an agent catalog so teams can apply rate limiting, security and observability policies to AI agent and Model Context Protocol traffic.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('64537204-ede8-4be9-b3b2-bb1a6ffab1aa', $q$Where is Gravitee headquartered$q$, $q$Gravitee is headquartered in Denver, Colorado, with additional engineering and commercial offices in Lille, France and London, United Kingdom.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('64537204-ede8-4be9-b3b2-bb1a6ffab1aa', $q$Who are Gravitee's main competitors$q$, $q$Gravitee competes most directly with Kong, Google Apigee, Salesforce MuleSoft, WSO2 and Tyk in the API management space.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('64537204-ede8-4be9-b3b2-bb1a6ffab1aa', $q$Enterprise API governance$q$, $q$Centralizing design, security and monitoring for hundreds of internal and partner-facing APIs behind a consistent gateway and access policy.$q$, $q$Platform and integration engineering teams at mid-market to large enterprises$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('64537204-ede8-4be9-b3b2-bb1a6ffab1aa', $q$Event-driven architecture mediation$q$, $q$Applying access control, schema governance and monitoring to Kafka topics and event streams alongside conventional REST APIs.$q$, $q$Streaming and event-driven architecture teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('64537204-ede8-4be9-b3b2-bb1a6ffab1aa', $q$AI agent and MCP governance$q$, $q$Applying rate limits, authentication and observability to AI agents and Model Context Protocol servers as they connect to internal systems.$q$, $q$Platform teams rolling out enterprise AI agents$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('64537204-ede8-4be9-b3b2-bb1a6ffab1aa', $q$Community Edition$q$, $q$Free$q$, $q$N/A (self-hosted, open source)$q$, NULL, $q$["Apache 2.0 licensed core gateway","API portal and basic analytics","Self-hosted deployment","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('64537204-ede8-4be9-b3b2-bb1a6ffab1aa', $q$Planet$q$, $q$$2,500/month$q$, $q$Monthly$q$, NULL, $q$["1 production gateway","Unlimited users and APIs","Unlimited API calls","Gold support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('64537204-ede8-4be9-b3b2-bb1a6ffab1aa', $q$Galaxy$q$, $q$Custom$q$, $q$Custom$q$, NULL, $q$["2 production gateways","Event broker support","Enterprise plugins","Gold support with consumption model option"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('64537204-ede8-4be9-b3b2-bb1a6ffab1aa', $q$Universe$q$, $q$Custom$q$, $q$Custom$q$, NULL, $q$["4+ production gateways","Unlimited enterprise functionality","All event brokers supported","Technical account manager and 24/7 support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('64537204-ede8-4be9-b3b2-bb1a6ffab1aa', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Gravitee began life in 2015 as an open-source API gateway built by a small team of developers in Lille, France who wanted a complete, freely available alternative to the expensive proprietary API management suites of the time.$q$, $q$A decade later the company has grown into a full platform spanning API management, event broker mediation, and, most recently, AI agent and MCP protocol governance, while keeping its original open-source Community Edition free and Apache 2.0 licensed.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('64537204-ede8-4be9-b3b2-bb1a6ffab1aa', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At the core of Gravitee is a protocol-agnostic API Gateway that can front REST, GraphQL, gRPC and event-streaming traffic from a single deployment, alongside an Access Management module for OAuth2 and OIDC identity flows.$q$, $q$Newer additions include an LLM proxy and MCP proxy for governing AI agent traffic with the same policies, rate limits and observability applied to conventional APIs, plus Cockpit, a central control plane for managing multiple gateways and environments.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('64537204-ede8-4be9-b3b2-bb1a6ffab1aa', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Gravitee prices its API Management line by number of production gateways rather than call volume, starting at Planet for $2,500 per month with unlimited users, APIs and calls on a single gateway, and scaling to custom-priced Galaxy and Universe tiers for larger deployments.$q$, $q$A parallel Event Management line for Kafka-style workloads starts at Comet for $1,250 per month, and the underlying Community Edition remains free and self-hostable for teams that only need the open-source gateway.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('64537204-ede8-4be9-b3b2-bb1a6ffab1aa', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('64537204-ede8-4be9-b3b2-bb1a6ffab1aa', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('64537204-ede8-4be9-b3b2-bb1a6ffab1aa', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('64537204-ede8-4be9-b3b2-bb1a6ffab1aa', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('64537204-ede8-4be9-b3b2-bb1a6ffab1aa', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('64537204-ede8-4be9-b3b2-bb1a6ffab1aa', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5f805c48-e5b0-4af0-83dd-98deb8ee69d9', $q$Centralized log ingestion$q$, $q$Collects and normalizes logs from servers, applications, network devices and security tools into one searchable index.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5f805c48-e5b0-4af0-83dd-98deb8ee69d9', $q$Custom search and dashboards$q$, $q$A purpose-built query language and configurable dashboards for exploring log data and building operational views.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5f805c48-e5b0-4af0-83dd-98deb8ee69d9', $q$Alerting engine$q$, $q$Rule-based alerting that notifies teams of anomalies, outages or security events as they happen.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5f805c48-e5b0-4af0-83dd-98deb8ee69d9', $q$SIEM correlation and threat intelligence$q$, $q$In the Security tier, correlation rules and threat intelligence feeds help detect and prioritize genuine security incidents.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5f805c48-e5b0-4af0-83dd-98deb8ee69d9', $q$Role-based access control$q$, $q$Granular permissions so different teams can access only the log streams and dashboards relevant to them.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5f805c48-e5b0-4af0-83dd-98deb8ee69d9', $q$Volume-based licensing$q$, $q$Enterprise and Security plans are priced by daily ingest volume, aligning cost with actual data usage rather than seat count.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5f805c48-e5b0-4af0-83dd-98deb8ee69d9', $q$Archiving and retention controls$q$, $q$Configurable data retention and archiving to meet compliance and audit requirements.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5f805c48-e5b0-4af0-83dd-98deb8ee69d9', $q$Open, source-available core$q$, $q$A free edition built on the same core engine as the paid tiers, allowing teams to start without a licensing commitment.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5f805c48-e5b0-4af0-83dd-98deb8ee69d9', $q$Genuinely capable free Open edition rather than a crippled trial version$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5f805c48-e5b0-4af0-83dd-98deb8ee69d9', $q$Volume-based pricing can be cost-effective for data-heavy but analyst-lean teams$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5f805c48-e5b0-4af0-83dd-98deb8ee69d9', $q$Built on familiar, widely understood search technology (Elasticsearch/OpenSearch)$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5f805c48-e5b0-4af0-83dd-98deb8ee69d9', $q$Clear upgrade path from free log management into full SIEM without switching platforms$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5f805c48-e5b0-4af0-83dd-98deb8ee69d9', $q$Enterprise and Security pricing is not published and requires a sales quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5f805c48-e5b0-4af0-83dd-98deb8ee69d9', $q$Self-managing the Open edition at scale requires real infrastructure and Elasticsearch/OpenSearch expertise$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5f805c48-e5b0-4af0-83dd-98deb8ee69d9', $q$Smaller analyst and integration ecosystem than incumbents like Splunk or QRadar$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5f805c48-e5b0-4af0-83dd-98deb8ee69d9', $q$Volume-based pricing can become expensive quickly for organizations with high daily log volume$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5f805c48-e5b0-4af0-83dd-98deb8ee69d9', $q$Is Graylog free to use$q$, $q$Yes. Graylog Open is a free, source-available edition that provides log collection, storage, search and basic analysis, though it lacks the advanced alerting, SIEM and support features of the paid tiers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5f805c48-e5b0-4af0-83dd-98deb8ee69d9', $q$How much does Graylog Enterprise cost$q$, $q$Graylog Enterprise starts at roughly 15,000 US dollars per year, billed based on daily data volume or annual consumption rather than per user.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5f805c48-e5b0-4af0-83dd-98deb8ee69d9', $q$Is Graylog a SIEM tool$q$, $q$Graylog Security is Graylog's dedicated SIEM product, adding correlation, threat intelligence and risk scoring on top of the core log management platform used by Graylog Open and Enterprise.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5f805c48-e5b0-4af0-83dd-98deb8ee69d9', $q$Who founded Graylog$q$, $q$Graylog was founded by Lennart Koopmann, who started the open-source Graylog2 project in 2009, with Hass Chapman joining as co-founder in 2012 to help build the company.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5f805c48-e5b0-4af0-83dd-98deb8ee69d9', $q$What is Graylog built on$q$, $q$Graylog's search and storage layer is built on Elasticsearch and OpenSearch, with a custom query language, dashboards and alerting layered on top.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5f805c48-e5b0-4af0-83dd-98deb8ee69d9', $q$Who competes with Graylog$q$, $q$Graylog's main competitors include Splunk, Elastic Security, IBM QRadar, LogRhythm and the open-source ELK/OpenSearch stack.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5f805c48-e5b0-4af0-83dd-98deb8ee69d9', $q$IT operations troubleshooting$q$, $q$Centralizing application and infrastructure logs so IT teams can quickly diagnose outages and performance issues.$q$, $q$IT operations and DevOps teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5f805c48-e5b0-4af0-83dd-98deb8ee69d9', $q$Security monitoring and threat detection$q$, $q$Using correlation rules and threat intelligence in Graylog Security to detect and triage security incidents with a lean SOC team.$q$, $q$Security operations center analysts$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5f805c48-e5b0-4af0-83dd-98deb8ee69d9', $q$Compliance log retention$q$, $q$Meeting regulatory data retention and audit requirements with configurable archiving and access controls.$q$, $q$Compliance and risk teams at regulated companies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5f805c48-e5b0-4af0-83dd-98deb8ee69d9', $q$Graylog Open$q$, $q$Free$q$, $q$N/A (source-available, self-hosted)$q$, NULL, $q$["Log collection, storage and search","Basic dashboards and alerting","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5f805c48-e5b0-4af0-83dd-98deb8ee69d9', $q$Graylog Enterprise$q$, $q$From $15,000/year$q$, $q$Annual, billed by data volume$q$, NULL, $q$["Advanced alerting and archiving","Higher-availability configuration options","Technical support","Designed for IT operations and DevOps teams"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5f805c48-e5b0-4af0-83dd-98deb8ee69d9', $q$Graylog Security$q$, $q$From $18,000/year$q$, $q$Annual, billed by data volume$q$, NULL, $q$["Full SIEM correlation engine","Threat intelligence integration","Risk scoring and alert fatigue reduction","Technical support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5f805c48-e5b0-4af0-83dd-98deb8ee69d9', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Graylog started in 2009 as an open-source side project by German developer Lennart Koopmann, who built his own log management tool after finding commercial alternatives too expensive, and it grew into a company co-founded with Hass Chapman in 2012.$q$, $q$The platform now spans a free, source-available Open edition and paid Enterprise and Security tiers built on the same log ingestion and search engine, serving both IT operations and security operations use cases.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5f805c48-e5b0-4af0-83dd-98deb8ee69d9', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Graylog centralizes logs from servers, applications, network devices and security tools into a searchable, indexed store, with dashboards, custom queries and alerting built on top.$q$, $q$The Security tier adds SIEM capabilities such as correlation rules, threat intelligence integration and risk scoring aimed at reducing alert fatigue for lean security teams.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5f805c48-e5b0-4af0-83dd-98deb8ee69d9', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Graylog Open is free and source-available for teams that want self-managed log collection and search without a subscription.$q$, $q$Graylog Enterprise starts at roughly 15,000 dollars per year and Graylog Security starts at roughly 18,000 dollars per year, both billed based on daily data volume or annual consumption rather than per user.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5f805c48-e5b0-4af0-83dd-98deb8ee69d9', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5f805c48-e5b0-4af0-83dd-98deb8ee69d9', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5f805c48-e5b0-4af0-83dd-98deb8ee69d9', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5f805c48-e5b0-4af0-83dd-98deb8ee69d9', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5f805c48-e5b0-4af0-83dd-98deb8ee69d9', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5f805c48-e5b0-4af0-83dd-98deb8ee69d9', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('baf8d62c-e7cc-47b0-a3b3-4bebcddf4b87', $q$200,000+ vulnerability tests$q$, $q$A continuously updated feed of vulnerability tests covering known CVEs, missing patches and common misconfigurations.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('baf8d62c-e7cc-47b0-a3b3-4bebcddf4b87', $q$Hardware and virtual appliances$q$, $q$OpenVAS Scan is available as a physical appliance or a virtual machine, supporting flexible on-premises deployment.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('baf8d62c-e7cc-47b0-a3b3-4bebcddf4b87', $q$GDPR-compliant architecture$q$, $q$Scan data can be kept entirely within the customer's own infrastructure, aligning with strict European data protection requirements.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('baf8d62c-e7cc-47b0-a3b3-4bebcddf4b87', $q$Centralized multi-scanner management$q$, $q$OpenVAS Security Intelligence consolidates reporting from multiple distributed scan instances into one risk view.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('baf8d62c-e7cc-47b0-a3b3-4bebcddf4b87', $q$CSAF and SBOM integration$q$, $q$Ingests CSAF security advisories and software bill of materials data for a more complete vulnerability and supply-chain picture.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('baf8d62c-e7cc-47b0-a3b3-4bebcddf4b87', $q$On-premises AI prioritization$q$, $q$OpenVAS AI turns raw scan results into prioritized remediation plans without sending data outside the customer's network.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('baf8d62c-e7cc-47b0-a3b3-4bebcddf4b87', $q$Open-source community edition$q$, $q$The core GVM/OpenVAS engine is free and open source, allowing self-hosted use without a commercial license.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('baf8d62c-e7cc-47b0-a3b3-4bebcddf4b87', $q$ISO-certified operations$q$, $q$ISO 9001, ISO 27001 and ISO 14001 certifications support procurement in regulated and public-sector environments.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('baf8d62c-e7cc-47b0-a3b3-4bebcddf4b87', $q$Free, actively maintained open-source scan engine with a long track record dating back to 2008$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('baf8d62c-e7cc-47b0-a3b3-4bebcddf4b87', $q$Strong GDPR and data-residency positioning, with on-premises deployment options for sensitive environments$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('baf8d62c-e7cc-47b0-a3b3-4bebcddf4b87', $q$Close historical ties to Germany's BSI federal security authority lend added credibility$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('baf8d62c-e7cc-47b0-a3b3-4bebcddf4b87', $q$Flexible deployment via hardware appliance, virtual appliance, or self-hosted open source$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('baf8d62c-e7cc-47b0-a3b3-4bebcddf4b87', $q$Commercial pricing is not published and requires going through a sales quote process$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('baf8d62c-e7cc-47b0-a3b3-4bebcddf4b87', $q$Hardware appliance procurement can be slower and less flexible than pure cloud-based competitors$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('baf8d62c-e7cc-47b0-a3b3-4bebcddf4b87', $q$Smaller global brand recognition than Tenable, Qualys or Rapid7 outside Europe$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('baf8d62c-e7cc-47b0-a3b3-4bebcddf4b87', $q$Newer AI and centralized intelligence features are still rolling out and less mature than the core scanner$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('baf8d62c-e7cc-47b0-a3b3-4bebcddf4b87', $q$Is Greenbone the same as OpenVAS$q$, $q$Greenbone is the company that leads development of OpenVAS (now formally the Greenbone Vulnerability Management framework) and sells commercial appliances and services built on top of that open-source engine.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('baf8d62c-e7cc-47b0-a3b3-4bebcddf4b87', $q$Is Greenbone free to use$q$, $q$The core open-source scanning engine can be self-hosted for free, and the entry-level OpenVAS Basic commercial tier offers a free 14-day trial, but the full appliance and enterprise product lines are paid and quote-based.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('baf8d62c-e7cc-47b0-a3b3-4bebcddf4b87', $q$How much does Greenbone cost$q$, $q$Greenbone does not publish list prices; customers request a quote based on appliance type, number of scanned assets and support level.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('baf8d62c-e7cc-47b0-a3b3-4bebcddf4b87', $q$Is Greenbone GDPR compliant$q$, $q$Yes. Greenbone markets its products as fully GDPR-compliant and supports on-premises deployments so vulnerability scan data never has to leave the customer's own infrastructure.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('baf8d62c-e7cc-47b0-a3b3-4bebcddf4b87', $q$Where is Greenbone based$q$, $q$Greenbone is headquartered in Osnabruck, Germany, and operates as the Greenbone Group with subsidiaries in the United Kingdom, Italy and the Netherlands.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('baf8d62c-e7cc-47b0-a3b3-4bebcddf4b87', $q$Who competes with Greenbone$q$, $q$Greenbone competes with Tenable (Nessus), Qualys, Rapid7 InsightVM and Microsoft Defender Vulnerability Management in the vulnerability management space.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('baf8d62c-e7cc-47b0-a3b3-4bebcddf4b87', $q$Enterprise vulnerability scanning$q$, $q$Running scheduled scans across servers, endpoints and network devices to find and prioritize missing patches and misconfigurations.$q$, $q$IT security teams at mid-size and large enterprises$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('baf8d62c-e7cc-47b0-a3b3-4bebcddf4b87', $q$Public sector and regulated compliance$q$, $q$Meeting GDPR and government security requirements with on-premises scanning that keeps vulnerability data within national or organizational boundaries.$q$, $q$Government agencies and critical infrastructure operators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('baf8d62c-e7cc-47b0-a3b3-4bebcddf4b87', $q$Small business entry-level scanning$q$, $q$Installing OpenVAS Basic to quickly identify and remediate obvious security weaknesses without a large security team.$q$, $q$Small businesses and individual IT administrators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('baf8d62c-e7cc-47b0-a3b3-4bebcddf4b87', $q$Community Edition (GVM/OpenVAS)$q$, $q$Free$q$, $q$N/A (self-hosted, open source)$q$, NULL, $q$["Core vulnerability scanning engine","Community-maintained vulnerability tests","Self-hosted deployment"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('baf8d62c-e7cc-47b0-a3b3-4bebcddf4b87', $q$OpenVAS Basic$q$, $q$Contact for pricing (free 14-day trial)$q$, $q$Custom$q$, NULL, $q$["Entry-level scanning for small companies and individuals","Simple install, scan and act workflow","GDPR-compliant design"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('baf8d62c-e7cc-47b0-a3b3-4bebcddf4b87', $q$OpenVAS Scan$q$, $q$Contact for pricing$q$, $q$Custom$q$, NULL, $q$["200,000+ vulnerability tests","Hardware or virtual appliance deployment","Best-in-market detection rate positioning"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('baf8d62c-e7cc-47b0-a3b3-4bebcddf4b87', $q$OpenVAS Security Intelligence$q$, $q$Contact for pricing$q$, $q$Custom$q$, NULL, $q$["Centralized management of distributed scanners","CSAF advisory integration","SBOM data integration"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('baf8d62c-e7cc-47b0-a3b3-4bebcddf4b87', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Greenbone was founded in 2008 in Osnabruck, Germany to lead development of OpenVAS, an open-source fork of the Nessus vulnerability scanner, and has since grown that project into a full vulnerability management platform sold as appliances and software.$q$, $q$The company converted to a German stock corporation (Greenbone AG) in 2023 and now operates as the Greenbone Group with subsidiaries in the UK, Italy and the Netherlands, reporting more than 100,000 protected installations across over 150 countries.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('baf8d62c-e7cc-47b0-a3b3-4bebcddf4b87', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Greenbone's core scan engine runs more than 200,000 vulnerability tests to identify missing patches, misconfigurations and known CVEs across an organization's IT assets.$q$, $q$Its product line spans an entry-level OpenVAS Basic tier, the flagship OpenVAS Scan appliance available in hardware or virtual form, and newer centralized management and on-premises AI prioritization capabilities.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('baf8d62c-e7cc-47b0-a3b3-4bebcddf4b87', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Greenbone does not publish list prices for its commercial appliances; customers submit a product request and receive a custom quote, with a free 14-day trial available for the entry-level OpenVAS Basic tier.$q$, $q$The underlying open-source Greenbone Vulnerability Management (GVM) engine, historically branded OpenVAS, remains free to self-host for organizations that only need the core scanning capability.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('baf8d62c-e7cc-47b0-a3b3-4bebcddf4b87', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('baf8d62c-e7cc-47b0-a3b3-4bebcddf4b87', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('baf8d62c-e7cc-47b0-a3b3-4bebcddf4b87', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('baf8d62c-e7cc-47b0-a3b3-4bebcddf4b87', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('baf8d62c-e7cc-47b0-a3b3-4bebcddf4b87', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('baf8d62c-e7cc-47b0-a3b3-4bebcddf4b87', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('69afcc2a-09a4-49b5-a478-dc5c7b9d0240', $q$Structured hiring and scorecards$q$, $q$Standardized interview kits and scorecards applied consistently across candidates to reduce bias and improve evaluation quality.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('69afcc2a-09a4-49b5-a478-dc5c7b9d0240', $q$Candidate relationship management (CRM)$q$, $q$Tools for proactively building and nurturing talent pipelines ahead of open requisitions.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('69afcc2a-09a4-49b5-a478-dc5c7b9d0240', $q$Scheduling automation$q$, $q$Automated interview scheduling that coordinates across interviewers, candidates and calendars.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('69afcc2a-09a4-49b5-a478-dc5c7b9d0240', $q$Reporting and analytics$q$, $q$Dashboards for tracking recruiting funnel metrics, time-to-hire and diversity of candidate pipelines.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('69afcc2a-09a4-49b5-a478-dc5c7b9d0240', $q$Sourcing automation$q$, $q$Automated outreach and pipeline-building tools available on the Plus and Pro tiers.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('69afcc2a-09a4-49b5-a478-dc5c7b9d0240', $q$Fraud detection$q$, $q$Tools designed to flag fabricated candidates or AI-generated interview responses.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('69afcc2a-09a4-49b5-a478-dc5c7b9d0240', $q$Extensive integration marketplace$q$, $q$Pre-built integrations with background check, assessment, HRIS and job board vendors.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('69afcc2a-09a4-49b5-a478-dc5c7b9d0240', $q$Enterprise governance controls$q$, $q$Audit logs, developer sandbox and enterprise data security available on the Pro tier for large, multi-region organizations.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('69afcc2a-09a4-49b5-a478-dc5c7b9d0240', $q$Structured, scorecard-based hiring methodology is well regarded for improving consistency and reducing bias$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('69afcc2a-09a4-49b5-a478-dc5c7b9d0240', $q$One of the largest third-party integration marketplaces among applicant tracking systems$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('69afcc2a-09a4-49b5-a478-dc5c7b9d0240', $q$Strong brand recognition and reference base among fast-growing technology companies$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('69afcc2a-09a4-49b5-a478-dc5c7b9d0240', $q$Three-tier structure lets organizations grow from basic ATS use into full enterprise hiring governance$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('69afcc2a-09a4-49b5-a478-dc5c7b9d0240', $q$No published pricing, requiring a sales-assisted quote for even basic evaluation$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('69afcc2a-09a4-49b5-a478-dc5c7b9d0240', $q$No self-serve free trial or free plan for smaller teams to test the product$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('69afcc2a-09a4-49b5-a478-dc5c7b9d0240', $q$Can be more complex and heavier to configure than lightweight ATS competitors for very small teams$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('69afcc2a-09a4-49b5-a478-dc5c7b9d0240', $q$Some advanced features such as fraud detection and BI connectors are locked behind higher-priced tiers$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('69afcc2a-09a4-49b5-a478-dc5c7b9d0240', $q$How much does Greenhouse cost$q$, $q$Greenhouse does not publish fixed prices. Cost is customized based on the Core, Plus or Pro plan selected, hiring volume, organizational complexity and required features, determined through a sales quote.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('69afcc2a-09a4-49b5-a478-dc5c7b9d0240', $q$Who founded Greenhouse$q$, $q$Greenhouse was founded in 2012 by Daniel Chait and Jon Stross, both University of Michigan graduates, with the goal of making hiring more structured and less biased.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('69afcc2a-09a4-49b5-a478-dc5c7b9d0240', $q$Is Greenhouse owned by TPG$q$, $q$TPG became Greenhouse's majority owner in January 2021 through a combined 47 million dollar primary investment and a 450 million dollar purchase of shares from existing investors.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('69afcc2a-09a4-49b5-a478-dc5c7b9d0240', $q$What is structured hiring in Greenhouse$q$, $q$Structured hiring refers to Greenhouse's methodology of standardized interview kits and scorecards applied consistently to every candidate for a role, intended to improve decision quality and reduce bias.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('69afcc2a-09a4-49b5-a478-dc5c7b9d0240', $q$Does Greenhouse offer a free trial$q$, $q$Greenhouse does not publicly advertise a self-serve free trial or free plan; prospective customers go through a demo and custom quote process instead.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('69afcc2a-09a4-49b5-a478-dc5c7b9d0240', $q$Who are Greenhouse's main competitors$q$, $q$Greenhouse's main competitors include Lever, Workday Recruiting, iCIMS, SmartRecruiters and Ashby.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('69afcc2a-09a4-49b5-a478-dc5c7b9d0240', $q$Scaling technology company hiring$q$, $q$Standardizing recruiting workflows and interview processes as a company scales from dozens to thousands of annual hires.$q$, $q$Talent acquisition teams at high-growth technology companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('69afcc2a-09a4-49b5-a478-dc5c7b9d0240', $q$Reducing hiring bias$q$, $q$Using structured scorecards and standardized interview kits to apply consistent evaluation criteria across all candidates for a role.$q$, $q$HR and DEI-focused hiring teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('69afcc2a-09a4-49b5-a478-dc5c7b9d0240', $q$Enterprise multi-region recruiting governance$q$, $q$Managing complex, multi-country hiring with audit logs, enterprise security and a developer sandbox for custom integrations.$q$, $q$Enterprise HR and IT teams at large, multi-region organizations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('69afcc2a-09a4-49b5-a478-dc5c7b9d0240', $q$Core$q$, $q$Custom quote$q$, $q$Custom$q$, NULL, $q$["Sourcing and CRM","Structured interviews and scorecards","Scheduling","Standard reporting","Single sign-on (SSO)","Real Talent candidate matching"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('69afcc2a-09a4-49b5-a478-dc5c7b9d0240', $q$Plus$q$, $q$Custom quote$q$, $q$Custom$q$, NULL, $q$["Everything in Core","AI-powered report filters","Business Intelligence Connector","Sourcing automation","Candidate texting","Fraud detection"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('69afcc2a-09a4-49b5-a478-dc5c7b9d0240', $q$Pro$q$, $q$Custom quote$q$, $q$Custom$q$, NULL, $q$["Everything in Plus","Unlimited CRM events","Enterprise-grade data security","Audit logs","Developer sandbox","Enterprise-level Real Talent features"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('69afcc2a-09a4-49b5-a478-dc5c7b9d0240', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Greenhouse was founded in 2012 in New York by Daniel Chait and Jon Stross to bring more structure and less bias to corporate hiring, and it grew into one of the most widely adopted applicant tracking systems among technology companies.$q$, $q$In January 2021, growth equity firm TPG took a majority stake in Greenhouse through a combined primary investment and secondary share purchase valuing the company at roughly 820 million dollars, shifting it from a purely venture-backed company to a private-equity-controlled one.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('69afcc2a-09a4-49b5-a478-dc5c7b9d0240', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Greenhouse combines an applicant tracking system, a candidate relationship management and sourcing layer, and scheduling and analytics into one platform built around structured, scorecard-based interviewing.$q$, $q$Higher tiers add AI-powered reporting, sourcing automation, candidate texting, fraud detection for fabricated candidates, and enterprise governance features like audit logs and a developer sandbox.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('69afcc2a-09a4-49b5-a478-dc5c7b9d0240', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Greenhouse sells three tiers, Core, Plus and Pro, each targeted at a different stage of hiring maturity and organizational complexity, but none publishes a fixed price.$q$, $q$Pricing is customized based on plan, hiring volume and required features, so prospective customers must request a demo or quote from Greenhouse's sales team.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('69afcc2a-09a4-49b5-a478-dc5c7b9d0240', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('69afcc2a-09a4-49b5-a478-dc5c7b9d0240', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('69afcc2a-09a4-49b5-a478-dc5c7b9d0240', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db5079b7-d737-4eb2-99fe-040725cc7508', $q$Geo-grid rank tracking$q$, $q$Visualizes Google Maps rankings as a grid of pins across a service area rather than a single average position.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db5079b7-d737-4eb2-99fe-040725cc7508', $q$Automated continuous monitoring$q$, $q$Re-scans rankings on a roughly three-day cadence with alerts when positions change significantly.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db5079b7-d737-4eb2-99fe-040725cc7508', $q$Google Business Profile management$q$, $q$Direct GBP integration for editing listings, with AI-driven alerts on unauthorized profile changes.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db5079b7-d737-4eb2-99fe-040725cc7508', $q$AI review response automation$q$, $q$AI agents that draft and post responses to customer reviews automatically.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db5079b7-d737-4eb2-99fe-040725cc7508', $q$Citation manager$q$, $q$Checks and helps correct business listing consistency across more than 1,000 online directories.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db5079b7-d737-4eb2-99fe-040725cc7508', $q$Competitor tracking$q$, $q$Benchmarks a business's local rankings against nearby competitors.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db5079b7-d737-4eb2-99fe-040725cc7508', $q$White-label agency reporting$q$, $q$Multi-location management with bulk actions and branded reports for agencies managing many client accounts.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db5079b7-d737-4eb2-99fe-040725cc7508', $q$MCP server for AI assistants$q$, $q$Gives AI tools direct, read-only access to local SEO account data without manual exports.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('db5079b7-d737-4eb2-99fe-040725cc7508', $q$Genuinely free Starter tier rather than a time-limited trial$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('db5079b7-d737-4eb2-99fe-040725cc7508', $q$Visual geo-grid format makes uneven local rankings easy to spot at a glance$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('db5079b7-d737-4eb2-99fe-040725cc7508', $q$Strong native Google Business Profile management alongside rank tracking, not just reporting$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('db5079b7-d737-4eb2-99fe-040725cc7508', $q$Built-in support for Service Area Businesses, which many local SEO tools handle poorly$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('db5079b7-d737-4eb2-99fe-040725cc7508', $q$Newer entrant to the geo-grid category with less brand history than Local Falcon or BrightLocal$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('db5079b7-d737-4eb2-99fe-040725cc7508', $q$Higher-volume scanning and competitor tracking are locked behind the Scale and Dominate tiers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('db5079b7-d737-4eb2-99fe-040725cc7508', $q$Publicly available company background information (founders, headquarters) is limited$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('db5079b7-d737-4eb2-99fe-040725cc7508', $q$Scan credit limits on lower tiers can be restrictive for agencies with many client locations$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('db5079b7-d737-4eb2-99fe-040725cc7508', $q$Is Grid My Business free$q$, $q$Yes. A free Starter tier includes 250 scan credits per month and covers two business profiles, with paid Growth, Scale and Dominate plans available for higher volume needs.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('db5079b7-d737-4eb2-99fe-040725cc7508', $q$What is geo-grid rank tracking$q$, $q$Geo-grid rank tracking shows how a business ranks on Google Maps across a grid of nearby locations, revealing where visibility is strong or weak rather than a single average ranking figure.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('db5079b7-d737-4eb2-99fe-040725cc7508', $q$Does Grid My Business support agencies$q$, $q$Yes. Grid My Business supports multi-location management, bulk actions and white-label reporting designed for agencies managing many client Google Business Profiles.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('db5079b7-d737-4eb2-99fe-040725cc7508', $q$Does Grid My Business work for service area businesses$q$, $q$Yes. The platform has built-in support for Service Area Businesses that serve a geographic radius rather than operating from a single storefront.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('db5079b7-d737-4eb2-99fe-040725cc7508', $q$How much does Grid My Business cost$q$, $q$Paid plans start at 29 dollars per month for Growth and go up to 89 dollars per month for Dominate, with annual billing offering a discount, alongside a free Starter tier.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('db5079b7-d737-4eb2-99fe-040725cc7508', $q$What is the Grid My Business MCP server$q$, $q$It is a Model Context Protocol server that gives AI assistants direct, read-only access to a customer's local SEO account data so metrics can be pulled without manual exports.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('db5079b7-d737-4eb2-99fe-040725cc7508', $q$Single-location local rank tracking$q$, $q$Monitoring how a small business ranks on Google Maps across its surrounding neighborhoods and adjusting SEO efforts accordingly.$q$, $q$Independent local business owners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('db5079b7-d737-4eb2-99fe-040725cc7508', $q$Agency multi-client reporting$q$, $q$Managing geo-grid tracking, review automation and white-label reports across dozens or hundreds of client locations.$q$, $q$Local SEO and digital marketing agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('db5079b7-d737-4eb2-99fe-040725cc7508', $q$Service area business visibility$q$, $q$Tracking and improving local search visibility for businesses that serve a radius rather than a fixed storefront address.$q$, $q$Home service providers such as plumbers, electricians and cleaners$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('db5079b7-d737-4eb2-99fe-040725cc7508', $q$Starter$q$, $q$Free$q$, $q$Monthly$q$, NULL, $q$["250 scan credits/month","2 business profiles","Basic geo-grid tracking"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('db5079b7-d737-4eb2-99fe-040725cc7508', $q$Growth$q$, $q$$29/month ($24/month billed annually at $290/year)$q$, $q$Monthly or annual$q$, NULL, $q$["~300 scans/month","Up to 100 business profiles","Up to 200 tracked competitors"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('db5079b7-d737-4eb2-99fe-040725cc7508', $q$Scale$q$, $q$$69/month ($58/month billed annually at $690/year)$q$, $q$Monthly or annual$q$, NULL, $q$["~800 scans/month","Up to 300 business profiles","Up to 600 tracked competitors"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('db5079b7-d737-4eb2-99fe-040725cc7508', $q$Dominate$q$, $q$$89/month ($74/month billed annually at $890/year)$q$, $q$Monthly or annual$q$, NULL, $q$["~1,200 scans/month","Unlimited business profiles","Up to 1,000 tracked competitors"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('db5079b7-d737-4eb2-99fe-040725cc7508', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Grid My Business launched in October 2021 as a visual geo-grid rank tracker that shows how a business ranks on Google Maps across many nearby locations at once, rather than a single average ranking.$q$, $q$The product has since grown into a fuller local SEO suite covering Google Business Profile management, review and post automation, citation management, and reporting for both individual businesses and agencies.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('db5079b7-d737-4eb2-99fe-040725cc7508', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core functionality centers on automated geo-grid scans that run roughly every three days, competitor tracking, and a GMB Score that combines rankings, profile completeness and review signals into one metric.$q$, $q$Additional tools include AI-powered review response automation, a post scheduler, a citation manager covering over 1,000 directories, and an MCP server that gives AI assistants direct access to account data.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('db5079b7-d737-4eb2-99fe-040725cc7508', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$A free Starter tier includes 250 scan credits per month and two business profiles, letting individual business owners try the platform at no cost.$q$, $q$Paid plans, Growth, Scale and Dominate, start at 29 dollars per month and scale up to 89 dollars per month based on scan volume, tracked profiles and competitors, with a 20 to 25 percent discount for annual billing.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('db5079b7-d737-4eb2-99fe-040725cc7508', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('db5079b7-d737-4eb2-99fe-040725cc7508', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('db5079b7-d737-4eb2-99fe-040725cc7508', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('db5079b7-d737-4eb2-99fe-040725cc7508', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('db5079b7-d737-4eb2-99fe-040725cc7508', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('085a00b0-0152-462a-8236-efd96d4561c7', $q$AI-powered matchmaking$q$, $q$Analyzes attendee profiles and preferences to automatically generate relevant one-to-one meeting suggestions.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('085a00b0-0152-462a-8236-efd96d4561c7', $q$White-label mobile event app$q$, $q$A customizable app providing schedules, exhibitor directories, floor plans and wayfinding for attendees.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('085a00b0-0152-462a-8236-efd96d4561c7', $q$Lead retrieval and scanning$q$, $q$Lets exhibitors capture and qualify leads through badge scanning integrated with the event app.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('085a00b0-0152-462a-8236-efd96d4561c7', $q$Multiple meeting formats$q$, $q$Supports over a dozen formats including hosted buyer sessions, speed networking, roundtables and investor meetings.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('085a00b0-0152-462a-8236-efd96d4561c7', $q$Onsite hardware tools$q$, $q$Badge printing, entrance scanning, smart badges and location tracking for physical events.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('085a00b0-0152-462a-8236-efd96d4561c7', $q$Sponsorship monetization$q$, $q$Tools that let organizers package and sell premium visibility and engagement opportunities to sponsors.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('085a00b0-0152-462a-8236-efd96d4561c7', $q$AI event assistant$q$, $q$An AI assistant that answers attendee questions instantly during an event to reduce support workload.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('085a00b0-0152-462a-8236-efd96d4561c7', $q$Modular platform architecture$q$, $q$Engagement, event management and onsite modules can be combined based on event format and size.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('085a00b0-0152-462a-8236-efd96d4561c7', $q$AI matchmaking engine is a mature, well-regarded core differentiator built over a decade$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('085a00b0-0152-462a-8236-efd96d4561c7', $q$Strong roster of marquee enterprise event customers including Money 20/20 and Messe Frankfurt$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('085a00b0-0152-462a-8236-efd96d4561c7', $q$Modular platform covers engagement, full event management and onsite hardware in one system$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('085a00b0-0152-462a-8236-efd96d4561c7', $q$Supports a wide range of meeting formats beyond simple one-to-one networking$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('085a00b0-0152-462a-8236-efd96d4561c7', $q$No published pricing; every deal requires a sales conversation and custom quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('085a00b0-0152-462a-8236-efd96d4561c7', $q$Built primarily for large enterprise events, which may be overkill or unaffordable for small event organizers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('085a00b0-0152-462a-8236-efd96d4561c7', $q$Onsite hardware tools add logistical complexity compared to purely software-based competitors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('085a00b0-0152-462a-8236-efd96d4561c7', $q$Feature depth can require significant setup and configuration ahead of an event$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('085a00b0-0152-462a-8236-efd96d4561c7', $q$What does Grip do$q$, $q$Grip is an AI-powered event technology platform that uses attendee data to generate matchmaking recommendations and provides a mobile event app, onsite tools and sponsorship features for conferences and trade shows.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('085a00b0-0152-462a-8236-efd96d4561c7', $q$How much does Grip cost$q$, $q$Grip does not publish pricing. It sells to enterprise event organizers through custom, per-event or annual contracts based on attendee volume and selected product modules.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('085a00b0-0152-462a-8236-efd96d4561c7', $q$Who founded Grip$q$, $q$Grip was founded in 2014 in London by Brent Hoberman, co-founder of lastminute.com, and Tim Groot.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('085a00b0-0152-462a-8236-efd96d4561c7', $q$Does Grip support in-person, virtual and hybrid events$q$, $q$Yes. Grip expanded from its original in-person matchmaking focus to fully support virtual and hybrid events during the COVID-19 pandemic and continues to support all three formats.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('085a00b0-0152-462a-8236-efd96d4561c7', $q$Who uses Grip$q$, $q$Grip is used by large event organizers and trade show producers including Money 20/20, Clarion Events, Messe Frankfurt and Reed Exhibitions.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('085a00b0-0152-462a-8236-efd96d4561c7', $q$Who competes with Grip$q$, $q$Grip competes with Bizzabo, Cvent, Swapcard and Brella in the event technology and matchmaking space.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('085a00b0-0152-462a-8236-efd96d4561c7', $q$Trade show attendee-exhibitor matchmaking$q$, $q$Using AI to connect trade show attendees with the most relevant exhibitors and sponsors automatically.$q$, $q$Large trade show and conference organizers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('085a00b0-0152-462a-8236-efd96d4561c7', $q$Hybrid and virtual conference engagement$q$, $q$Running networking, sessions and matchmaking for attendees participating both in person and remotely.$q$, $q$Corporate and association event teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('085a00b0-0152-462a-8236-efd96d4561c7', $q$Investor and hosted buyer meetings$q$, $q$Structuring dedicated investor meeting or hosted buyer programs with AI-recommended, scheduled one-to-one sessions.$q$, $q$Investment conference and B2B hosted buyer program organizers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('085a00b0-0152-462a-8236-efd96d4561c7', $q$Engagement$q$, $q$Custom quote$q$, $q$Custom, per-event or annual$q$, NULL, $q$["AI matchmaking","Mobile event app","Meeting formats"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('085a00b0-0152-462a-8236-efd96d4561c7', $q$Management$q$, $q$Custom quote$q$, $q$Custom, per-event or annual$q$, NULL, $q$["Full event management system","Exhibitor and sponsor management","Reporting and analytics"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('085a00b0-0152-462a-8236-efd96d4561c7', $q$Onsite$q$, $q$Custom quote$q$, $q$Custom, per-event or annual$q$, NULL, $q$["Badge printing and entrance scanning","Smart badges and location tracking","Lead retrieval"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('085a00b0-0152-462a-8236-efd96d4561c7', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Grip was founded in London in 2014 by Brent Hoberman, co-founder of lastminute.com, and Tim Groot, built around AI-driven attendee matchmaking for business events.$q$, $q$A pivot to virtual and hybrid events during the COVID-19 pandemic, followed by a 13 million dollar Series A round in February 2021, helped Grip expand into a full event technology platform used by major trade show and conference organizers.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('085a00b0-0152-462a-8236-efd96d4561c7', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Grip's core feature is AI-powered matchmaking that analyzes attendee data to generate relevant one-to-one meeting suggestions between attendees, exhibitors and sponsors.$q$, $q$The platform also includes a white-label mobile event app, more than a dozen meeting formats, onsite badge and lead retrieval tools, and sponsorship monetization capabilities.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('085a00b0-0152-462a-8236-efd96d4561c7', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Grip does not publish self-serve pricing because it sells to enterprise event organizers, trade show producers and conference companies through negotiated, per-event or annual contracts.$q$, $q$Pricing depends on attendee volume, which product modules (engagement, management, onsite) are selected, and the level of onsite hardware and support required.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('085a00b0-0152-462a-8236-efd96d4561c7', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('085a00b0-0152-462a-8236-efd96d4561c7', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('085a00b0-0152-462a-8236-efd96d4561c7', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('085a00b0-0152-462a-8236-efd96d4561c7', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('085a00b0-0152-462a-8236-efd96d4561c7', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b0a59332-e7cb-4428-afe9-3934017982dd', $q$Spreadsheet interface with database powers$q$, $q$A familiar grid editing experience backed by a real relational data model with enforced data types.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b0a59332-e7cb-4428-afe9-3934017982dd', $q$Python-based formulas$q$, $q$Formulas are written in real Python rather than a proprietary spreadsheet language, enabling more powerful logic.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b0a59332-e7cb-4428-afe9-3934017982dd', $q$Multiple data views$q$, $q$The same underlying data can be displayed as grid, card, chart or other custom layouts.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b0a59332-e7cb-4428-afe9-3934017982dd', $q$Cell-level access control$q$, $q$Permissions can be restricted down to specific rows, columns or individual cells.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b0a59332-e7cb-4428-afe9-3934017982dd', $q$REST API$q$, $q$Programmatic access to documents and data for integrations and automation.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b0a59332-e7cb-4428-afe9-3934017982dd', $q$AI Assistant$q$, $q$Helps users write formulas, clean data or build new views using natural language prompts.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b0a59332-e7cb-4428-afe9-3934017982dd', $q$Self-hosting via open source$q$, $q$The core grist-core engine is Apache 2.0 licensed and can be run entirely on a customer's own infrastructure.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b0a59332-e7cb-4428-afe9-3934017982dd', $q$Document snapshot history$q$, $q$Automatic version history of documents, with retention length varying by plan.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b0a59332-e7cb-4428-afe9-3934017982dd', $q$Fully open-source and self-hostable, avoiding vendor lock-in and supporting strict data residency needs$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b0a59332-e7cb-4428-afe9-3934017982dd', $q$Real relational data model under a familiar spreadsheet interface, more robust than plain spreadsheets at scale$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b0a59332-e7cb-4428-afe9-3934017982dd', $q$Python-based formulas are more powerful and transparent than typical proprietary spreadsheet formula languages$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b0a59332-e7cb-4428-afe9-3934017982dd', $q$Self-funded company culture with no venture capital growth pressure, plus nonprofit discounts$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b0a59332-e7cb-4428-afe9-3934017982dd', $q$Smaller ecosystem of templates and integrations compared to Airtable$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b0a59332-e7cb-4428-afe9-3934017982dd', $q$Free cloud plan's 5,000 record per document limit is restrictive for larger datasets$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b0a59332-e7cb-4428-afe9-3934017982dd', $q$Self-hosting requires technical setup and maintenance effort not needed with a fully managed SaaS$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b0a59332-e7cb-4428-afe9-3934017982dd', $q$AI Assistant credit allotments on lower tiers are limited compared to dedicated AI-first tools$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b0a59332-e7cb-4428-afe9-3934017982dd', $q$Is Grist free to use$q$, $q$Yes. Grist offers a free self-hosted Community Edition under an Apache 2.0 open-source license, as well as a free cloud-hosted plan with up to 5,000 records per document.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b0a59332-e7cb-4428-afe9-3934017982dd', $q$Can Grist be self-hosted$q$, $q$Yes. Grist's core engine, grist-core, along with grist-desktop and grist-static, is open source and can be run on a customer's own infrastructure, with a paid self-hosted Enterprise tier available for larger deployments.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b0a59332-e7cb-4428-afe9-3934017982dd', $q$How is Grist different from Airtable$q$, $q$Grist uses a familiar spreadsheet-style grid interface backed by a true relational data model and Python-based formulas, and it offers a fully open-source, self-hostable option, whereas Airtable is a closed, cloud-only platform.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b0a59332-e7cb-4428-afe9-3934017982dd', $q$How much does Grist cost$q$, $q$Grist's cloud plans start free, then Pro is 10 dollars per user per month (8 dollars billed annually), Business is 30 dollars per user per month with a 5-user minimum, and Enterprise is custom priced.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b0a59332-e7cb-4428-afe9-3934017982dd', $q$Who founded Grist$q$, $q$Grist Labs was founded in 2014 in New York City by brothers Dmitry and Stan Sagalovskiy and has remained self-funded without external venture capital.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b0a59332-e7cb-4428-afe9-3934017982dd', $q$Does Grist offer nonprofit discounts$q$, $q$Yes. Registered nonprofits receive a 50 percent discount on the Pro plan, and organizations with under 1 million dollars in annual revenue can request free activation.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b0a59332-e7cb-4428-afe9-3934017982dd', $q$Team database without a developer$q$, $q$Building linked, relational data tools for project tracking, inventories or CRM-style workflows without writing custom software.$q$, $q$Small teams and operations staff without dedicated engineering support$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b0a59332-e7cb-4428-afe9-3934017982dd', $q$Privacy-first self-hosted data management$q$, $q$Running Grist entirely on internal infrastructure to keep sensitive data off third-party cloud servers.$q$, $q$Privacy-conscious organizations, nonprofits and government teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b0a59332-e7cb-4428-afe9-3934017982dd', $q$Replacing fragile spreadsheets$q$, $q$Migrating large, error-prone Excel or Google Sheets workbooks into a more robust relational structure with enforced data types.$q$, $q$Analysts and operations teams outgrowing traditional spreadsheets$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b0a59332-e7cb-4428-afe9-3934017982dd', $q$Free (Cloud)$q$, $q$$0/user/month$q$, $q$Monthly$q$, NULL, $q$["Up to 5,000 records per document","100 AI Assistant credits (lifetime)","2 guests per document","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b0a59332-e7cb-4428-afe9-3934017982dd', $q$Community Edition (Self-Hosted)$q$, $q$Free$q$, $q$N/A (self-hosted, open source)$q$, NULL, $q$["Full open-source Grist engine","Self-hosted deployment","Community support only"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b0a59332-e7cb-4428-afe9-3934017982dd', $q$Pro$q$, $q$$10/user/month ($8/user/month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["Up to 100,000 records per document","3-year snapshot history","100 AI Assistant credits/month","Unlimited documents"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b0a59332-e7cb-4428-afe9-3934017982dd', $q$Business$q$, $q$$30/user/month ($24/user/month billed annually), 5-user minimum$q$, $q$Monthly or annual$q$, NULL, $q$["Up to 150,000 records per document","5-year snapshot history","2,000 AI Assistant credits/month","Automations and priority email support"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b0a59332-e7cb-4428-afe9-3934017982dd', $q$Enterprise$q$, $q$Custom$q$, $q$Custom$q$, NULL, $q$["Cloud-hosted or self-hosted","Custom SSO, domain and branding","Audit log streaming","Dedicated server with custom region"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b0a59332-e7cb-4428-afe9-3934017982dd', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Grist Labs was founded in 2014 in New York City by brothers Dmitry and Stan Sagalovskiy, who built Grist around the belief that open-source, self-hostable software was the best defense against the surveillance and vendor lock-in risks exposed by the 2013 Snowden disclosures.$q$, $q$The company has remained self-funded throughout its history and has open-sourced Grist's core engine under the Apache 2.0 license, letting anyone run a full Grist instance on their own infrastructure alongside the company's hosted cloud service.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b0a59332-e7cb-4428-afe9-3934017982dd', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Grist looks like a familiar spreadsheet but is backed by a real relational data model, so tables can be linked together with enforced data types even as documents grow large.$q$, $q$It supports Python-based formulas, multiple views over the same data (grid, card, chart), cell-level access control, a REST API, and an AI Assistant for writing formulas and building views with natural language.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b0a59332-e7cb-4428-afe9-3934017982dd', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Grist offers both a fully open-source, self-hosted Community Edition and a cloud-hosted Free plan, both at no cost, with the cloud Free plan capped at 5,000 records per document.$q$, $q$Paid cloud plans start at Pro for 10 dollars per user per month (8 dollars billed annually), rising to Business at 30 dollars per user per month, with a custom-priced Enterprise tier available both cloud-hosted and self-hosted.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b0a59332-e7cb-4428-afe9-3934017982dd', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
