INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8b23fc94-f6ee-4551-9707-24f01eb5e9e4', $q$Conversational AI assistant$q$, $q$Answers questions, explains concepts, and assists with writing, coding and reasoning tasks through natural conversation.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8b23fc94-f6ee-4551-9707-24f01eb5e9e4', $q$Real-time X data integration$q$, $q$Native access to live posts and trends on X gives Grok up-to-date awareness of breaking news and public conversation.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8b23fc94-f6ee-4551-9707-24f01eb5e9e4', $q$Grok Imagine (image and video generation)$q$, $q$Generates images and short videos from text prompts, extending Grok beyond a text-only chatbot.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8b23fc94-f6ee-4551-9707-24f01eb5e9e4', $q$Multimodal image analysis$q$, $q$Can analyze and answer questions about uploaded images and screenshots.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8b23fc94-f6ee-4551-9707-24f01eb5e9e4', $q$Rapid model iteration$q$, $q$Frequent flagship model releases (Grok 3, Grok 4, Grok 4.5) with expanding context windows and reasoning ability.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8b23fc94-f6ee-4551-9707-24f01eb5e9e4', $q$Cross-platform access$q$, $q$Available on the web at grok.com, inside X, and via dedicated iOS and Android apps.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8b23fc94-f6ee-4551-9707-24f01eb5e9e4', $q$Developer API$q$, $q$Programmatic access to Grok models priced per million input and output tokens for building custom applications.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8b23fc94-f6ee-4551-9707-24f01eb5e9e4', $q$Business plan$q$, $q$A dedicated per-user Grok Business subscription for organizational deployment.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8b23fc94-f6ee-4551-9707-24f01eb5e9e4', $q$Real-time integration with X gives Grok access to live public conversation and breaking news other chatbots lack$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8b23fc94-f6ee-4551-9707-24f01eb5e9e4', $q$Backed by extremely large capital raises, funding an unusually fast pace of model releases$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8b23fc94-f6ee-4551-9707-24f01eb5e9e4', $q$Genuinely usable free tier alongside multiple paid tiers for different budgets and usage levels$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8b23fc94-f6ee-4551-9707-24f01eb5e9e4', $q$Available across web, X, iOS and Android with a dedicated business plan for teams$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8b23fc94-f6ee-4551-9707-24f01eb5e9e4', $q$Free tier prompt limits (roughly 10 every two hours) are restrictive compared to some competitors' free tiers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8b23fc94-f6ee-4551-9707-24f01eb5e9e4', $q$Pricing structure is split confusingly across standalone SuperGrok plans and separate X Premium bundles$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8b23fc94-f6ee-4551-9707-24f01eb5e9e4', $q$Tight integration with Musk's other companies (X, SpaceX) raises questions about long-term platform independence$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8b23fc94-f6ee-4551-9707-24f01eb5e9e4', $q$Grok's less-filtered personality and content moderation approach has drawn scrutiny compared to more conservative competitors$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8b23fc94-f6ee-4551-9707-24f01eb5e9e4', $q$Is Grok free to use$q$, $q$Yes. Grok has a free tier offering roughly 10 prompts every two hours on a lighter model, alongside paid SuperGrok subscriptions for higher usage limits and access to flagship models.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8b23fc94-f6ee-4551-9707-24f01eb5e9e4', $q$What is the difference between SuperGrok and X Premium+$q$, $q$SuperGrok is a standalone subscription accessed directly through grok.com starting at 30 dollars per month, while X Premium+ at 40 dollars per month bundles Grok access together with ad-free browsing and other perks on the X platform.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8b23fc94-f6ee-4551-9707-24f01eb5e9e4', $q$Who owns Grok$q$, $q$Grok is built by xAI, which Elon Musk founded in 2023, acquired X in an all-stock deal in March 2025, and was itself acquired by SpaceX in February 2026.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8b23fc94-f6ee-4551-9707-24f01eb5e9e4', $q$Can I use Grok on mobile$q$, $q$Yes. Grok has dedicated iOS and Android apps, in addition to being accessible via the web at grok.com and within the X app.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8b23fc94-f6ee-4551-9707-24f01eb5e9e4', $q$Does Grok generate images and video$q$, $q$Yes. Grok Imagine, launched in July 2025, lets users generate images and short videos from text prompts.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8b23fc94-f6ee-4551-9707-24f01eb5e9e4', $q$How much does the Grok API cost$q$, $q$Grok API pricing varies by model; as of mid-2026 the flagship Grok 4.5 is priced at roughly 2 dollars per million input tokens and 6 dollars per million output tokens.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8b23fc94-f6ee-4551-9707-24f01eb5e9e4', $q$General AI assistant for everyday tasks$q$, $q$Answering questions, drafting content, summarizing information and helping with day-to-day writing tasks.$q$, $q$Individual consumers and knowledge workers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8b23fc94-f6ee-4551-9707-24f01eb5e9e4', $q$Developer integration via API$q$, $q$Building custom applications, chatbots or automations powered by Grok's language models.$q$, $q$Software developers and AI product teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8b23fc94-f6ee-4551-9707-24f01eb5e9e4', $q$Real-time news and social context analysis$q$, $q$Using Grok's live X data integration to summarize or analyze breaking news and public sentiment as it happens.$q$, $q$Journalists, analysts and social media managers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8b23fc94-f6ee-4551-9707-24f01eb5e9e4', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["~10 prompts every 2 hours","Access to a lighter Grok model","Basic web and app access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8b23fc94-f6ee-4551-9707-24f01eb5e9e4', $q$SuperGrok Lite$q$, $q$$10/month$q$, $q$Monthly$q$, NULL, $q$["Standalone Grok subscription","Higher usage limits than free tier","Introduced March 2026"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8b23fc94-f6ee-4551-9707-24f01eb5e9e4', $q$SuperGrok$q$, $q$$30/month ($300/year)$q$, $q$Monthly or annual$q$, NULL, $q$["Access to flagship Grok models","Higher usage limits","Grok Imagine access"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8b23fc94-f6ee-4551-9707-24f01eb5e9e4', $q$SuperGrok Heavy$q$, $q$$300/month$q$, $q$Monthly$q$, NULL, $q$["Guaranteed access to the most capable Grok model at all times","Highest usage limits","Priority access to new features"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8b23fc94-f6ee-4551-9707-24f01eb5e9e4', $q$X Premium$q$, $q$$8/month$q$, $q$Monthly$q$, NULL, $q$["Basic Grok access","Bundled X platform features"]$q$::jsonb, 4);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8b23fc94-f6ee-4551-9707-24f01eb5e9e4', $q$X Premium+$q$, $q$$40/month$q$, $q$Monthly$q$, NULL, $q$["Fuller Grok access","Ad-free X browsing","Higher message throughput"]$q$::jsonb, 5);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8b23fc94-f6ee-4551-9707-24f01eb5e9e4', $q$Grok Business$q$, $q$$30/user/month$q$, $q$Monthly, per user$q$, NULL, $q$["Organizational deployment","Business-oriented usage limits","Team management"]$q$::jsonb, 6);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8b23fc94-f6ee-4551-9707-24f01eb5e9e4', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Grok is the AI chatbot built by xAI, the company Elon Musk founded in March 2023 and launched publicly in July 2023, first shipping to X Premium subscribers in November 2023 before becoming a standalone product at grok.com and via iOS and Android apps worldwide in January 2025.$q$, $q$xAI has raised over 22 billion dollars across a rapid sequence of funding rounds, acquired X in an all-stock deal in March 2025, and was itself acquired by SpaceX in February 2026, consolidating Grok, X and SpaceX under shared Musk-controlled ownership.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8b23fc94-f6ee-4551-9707-24f01eb5e9e4', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Grok functions as a general-purpose conversational assistant for answering questions, writing and debugging code, reasoning through complex problems and analyzing images, with real-time access to live posts and trends from X.$q$, $q$Grok Imagine, launched in July 2025, extended the product into image and video generation from text prompts, and successive model releases (Grok 3, Grok 4, Grok 4.5) have steadily expanded context length and reasoning capability.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8b23fc94-f6ee-4551-9707-24f01eb5e9e4', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Grok offers a free tier with limited prompts, alongside standalone SuperGrok subscriptions: SuperGrok Lite at 10 dollars per month, SuperGrok at 30 dollars per month, and SuperGrok Heavy at 300 dollars per month for guaranteed top-tier model access.$q$, $q$Grok access is also bundled into X Premium (8 dollars per month) and X Premium+ (40 dollars per month), with a Grok Business plan at 30 dollars per user per month and usage-based API pricing for developers.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8b23fc94-f6ee-4551-9707-24f01eb5e9e4', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
