-- Enrichment marathon batch: Gravitee, Graylog, Greenbone, Greenhouse, Grid My Business, Grip, Grist, Grok

-- ── Gravitee ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Gravitee is an open-source-rooted API, event and AI agent management platform that lets enterprises design, secure, govern and monetize APIs and event streams from one gateway.$q$, short_description),
  pricing_model = COALESCE($q$Freemium (open-source Community Edition plus tiered commercial plans)$q$, pricing_model),
  starting_price = COALESCE($q$Free (Community Edition); paid plans from $1,250/month$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE($q$101-250 employees$q$, company_size),
  headquarters = COALESCE($q$Denver, Colorado, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$]::text[],
  seo_title = COALESCE($q$Gravitee Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Gravitee review covering API gateway and event management features, Community vs Enterprise pricing, AI agent tooling, pros, cons and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Gravitee is an API management and, increasingly, an AI agent management platform that grew out of an open-source project started by a small team of French developers who were frustrated that no single open-source stack covered the full API lifecycle, including a gateway, a developer portal and analytics. The company was founded in 2015 in Lille, France by CEO Rory Blundell together with developers Azize Elamrani, David Brassely, Nicolas Geraud and Titouan Compiegne. The founding team built and released Gravitee as Apache 2.0 licensed open source software first, then layered a commercial Enterprise Edition and hosted services on top once the community edition had proven itself with real adoption, a pattern common to open-core infrastructure companies such as Elastic and Kong. Over the following decade Gravitee relocated its formal headquarters to Denver, Colorado in the United States while keeping a significant engineering base in Lille and a European commercial office in London, reflecting its dual identity as a European-engineered product with a US-facing go-to-market motion. The company has raised meaningful outside capital to fund this expansion, including a $60 million Series C round announced in May 2025, bringing total disclosed funding to roughly $127 million from investors backing its push into event-native APIs and AI infrastructure. Today Gravitee employs a team in the low hundreds spread across its Denver, Lille and London offices. Architecturally, Gravitee is built around a lightweight, high-performance API Gateway that can front REST, GraphQL, gRPC, WebSocket and Kafka-based event traffic, paired with an Access Management module for OAuth2 and OpenID Connect identity flows, an API Designer for building and mocking APIs, an Alert Engine for real-time operational alerting, and Cockpit, a control plane for multi-gateway, multi-environment governance. Because the gateway is protocol-agnostic and can be deployed at the edge, in Kubernetes, or as a managed cloud service, Gravitee is positioned as a single control point across REST APIs, event brokers such as Kafka and Solace, and, in its newest product direction, AI agents and large language model traffic. The company's 2025 and 2026 roadmap has focused heavily on this AI agent management layer, adding an LLM proxy, an MCP (Model Context Protocol) proxy and an agent catalog so that organizations can apply the same governance, rate limiting, observability and security controls to AI agents and MCP servers that they already apply to conventional APIs, plus an Enterprise Auth add-on built on the OpenFGA permission engine. Commercially, Gravitee splits its offering into two parallel product lines, each licensed by the number of production gateways rather than by API call volume, which the company markets as unlimited API calls and events for one predictable monthly price. The API Management line runs Planet at $2,500 per month for a single production gateway with unlimited users and APIs, scaling through the custom-priced Galaxy tier (two gateways plus event broker support and enterprise plugins) up to Universe, a fully custom enterprise tier with four or more gateways, 24/7 support and a dedicated technical account manager. A parallel Event Management line, aimed at teams standardizing on Kafka-style event brokers, starts at Comet for $1,250 per month and scales through Meteor to Asteroid. Every paid tier includes free setup, onboarding and implementation with no separately billed usage fees, and the underlying Community Edition remains free and self-hostable under an Apache 2.0 license for teams that want the open-source gateway without commercial support. Gravitee's target buyer is a platform engineering, integration or API product team inside a mid-market to large enterprise, particularly in regulated industries like banking, insurance, telecom and healthcare where its European origin and self-hosting options resonate with data residency requirements. Its closest competitors are Kong, Apigee (Google), MuleSoft (Salesforce), WSO2 and Tyk, and Gravitee differentiates primarily on its open-source lineage and generous free community tier, its native support for event-driven and streaming protocols alongside REST, and its early, dedicated tooling for governing AI agent and MCP traffic rather than treating it as an afterthought bolted onto a legacy gateway.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '64537204-ede8-4be9-b3b2-bb1a6ffab1aa';

