-- ── Greenbone ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Greenbone is a German vulnerability management company behind OpenVAS, offering GDPR-compliant scanning appliances and software to find and prioritize IT security weaknesses.$q$, short_description),
  pricing_model = COALESCE($q$Open source plus commercial appliances and subscriptions (quote-based)$q$, pricing_model),
  starting_price = COALESCE($q$Free (OpenVAS/GVM open source); paid appliances via quote, free 14-day trial available$q$, starting_price),
  founded_year = COALESCE(2008, founded_year),
  company_size = COALESCE($q$101-250 employees$q$, company_size),
  headquarters = COALESCE($q$Osnabruck, Germany$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$]::text[],
  seo_title = COALESCE($q$Greenbone Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Greenbone review covering OpenVAS vulnerability scanning, appliance and cloud pricing, GDPR compliance, key features, pros, cons and alternatives for 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Greenbone is a German cybersecurity company built around OpenVAS, one of the longest-running open-source vulnerability scanning projects in the industry. The company, originally founded as Greenbone Networks in late 2008 in Osnabruck, Germany, took over leadership of the OpenVAS project (a fork of the earlier Nessus scanner after Nessus went closed-source) and progressively turned it from a standalone scanner into a full vulnerability management solution while deliberately keeping its free-software values intact. In 2023 the company restructured into Greenbone AG, a German stock corporation, reflecting its maturation from a scrappy open-source shop into an established security vendor with roughly 15 years of vulnerability research behind it. Greenbone has grown into what it now calls the Greenbone Group, with wholly owned subsidiaries in the United Kingdom, Italy and the Netherlands extending its reach beyond the German-speaking market, and the company reports that its technology protects more than 100,000 installations across over 150 countries, spanning private enterprises, healthcare providers and government agencies. As of the mid-2020s Greenbone employs roughly 115 to 120 people across offices on multiple continents. Notably, Greenbone has built a close relationship with Germany's Federal Office for Information Security (BSI), which has historically supported and referenced Greenbone's tooling, lending the company particular credibility in the German and broader European public sector, and it holds ISO 9001, ISO 27001 and ISO 14001 certifications that matter for enterprise and government procurement. Technically, Greenbone's core engine remains the open-source Greenbone Vulnerability Management (GVM) framework, historically branded OpenVAS, which runs more than 200,000 individual vulnerability tests (VTs) against target systems to identify missing patches, misconfigurations and known CVEs, and the company markets its detection rate as best-in-class. The product line is organized in tiers of increasing sophistication. OpenVAS Basic is the entry-level offering aimed at small companies and individual users, designed to be installed and run quickly with minimal configuration and offered with a free 14-day trial. OpenVAS Scan is the flagship product for companies and public institutions, available as both hardware and virtual appliances so organizations can choose on-premises or virtualized deployment depending on their infrastructure and data residency needs, and it forms the backbone of most commercial Greenbone deployments. Building on that, Greenbone has been rolling out OpenVAS Security Intelligence, a centralized management layer for organizations running many distributed OpenVAS Scan instances that also ingests CSAF security advisories and software bill of materials (SBOM) data to give a consolidated risk picture, and OpenVAS AI, an on-premises artificial intelligence capability designed to turn raw scan output into prioritized remediation action plans without any scan data leaving the customer's network, a deliberate design choice aligned with Greenbone's GDPR-first positioning. Pricing for Greenbone's commercial appliances and subscriptions is not published; prospective customers submit a product request and receive a custom quote based on the number of scanned assets, appliance model and support level required, though the underlying scan engine and vulnerability feed are also available in a community edition that can be self-hosted for free, consistent with the project's open-source origins. Greenbone's target customer ranges from small and mid-sized businesses buying an entry-level appliance to secure a limited environment, up to large enterprises, critical infrastructure operators and public-sector agencies in Europe that specifically value GDPR compliance and the ability to keep vulnerability data entirely within their own jurisdiction rather than sending it to a US-based cloud vendor. Its main competitors include Tenable (Nessus), Qualys, Rapid7 InsightVM and Microsoft Defender Vulnerability Management, and Greenbone differentiates primarily through its open-source heritage and community edition, its strict GDPR and data-residency posture, its long-standing relationship with German federal security authorities, and its emphasis on on-premises deployment options for organizations unwilling or unable to send scan data to a third-party cloud.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'baf8d62c-e7cc-47b0-a3b3-4bebcddf4b87';

