-- ── Greenhouse ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Greenhouse is an applicant tracking and hiring platform used by employers to structure recruiting, source and manage candidates, and reduce bias throughout the hiring process.$q$, short_description),
  pricing_model = COALESCE($q$Subscription, custom quote-based tiers$q$, pricing_model),
  starting_price = COALESCE($q$Custom pricing (no published starting price)$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE($q$501-1000 employees$q$, company_size),
  headquarters = COALESCE($q$New York, New York, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Greenhouse Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Greenhouse review covering ATS and recruiting features, Core, Plus and Pro pricing tiers, founding story, funding, pros, cons and top alternatives for 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Greenhouse is an applicant tracking system (ATS) and hiring platform that has become one of the most widely used recruiting technologies among mid-size and large employers, particularly technology companies. It was founded in 2012 by Daniel Chait and Jon Stross, both University of Michigan alumni from the class of 1995, who set out to build a more structured, less bias-prone approach to hiring after experiencing firsthand how ad hoc most companies' interview processes were. The company is headquartered in New York City and grew through a series of venture rounds: a 2.7 million dollar seed round in 2013, a 7.5 million dollar Series A in 2014, a 13.6 million dollar Series B in 2015, a 35 million dollar Series C later in 2015, and a 50 million dollar Series D in 2018, bringing total disclosed venture funding to roughly 110 million dollars across eight rounds from investors including Benchmark and Thrive Capital. The company's ownership structure changed significantly in January 2021, when growth equity firm TPG invested 47 million dollars in new capital at an 820 million dollar valuation and separately spent 450 million dollars purchasing shares from existing shareholders, giving TPG a majority stake in the company; that transaction effectively valued Greenhouse at well north of 1 billion dollars and marked its transition from a venture-backed startup to a private-equity-controlled scale-up. Today Greenhouse employs roughly 900 to 950 people and serves thousands of customers, including a significant share of fast-growing technology companies that adopted it as their default ATS during the 2010s hiring boom. Structurally, Greenhouse is built around three integrated modules: an Applicant Tracking System for managing requisitions, candidates and interview pipelines; a Candidate Relationship Management (CRM) and sourcing layer for proactively building talent pipelines before roles open; and a scheduling and analytics layer that helps recruiting teams measure funnel performance and time-to-hire. A defining product philosophy is Greenhouse's emphasis on structured hiring, meaning standardized interview kits, scorecards and defined evaluation criteria applied consistently across candidates for a given role, which the company positions as both a better candidate experience and a way to reduce unconscious bias in hiring decisions, an idea that has become one of Greenhouse's signature differentiators against more transactional ATS competitors. The product is organized into three named pricing tiers, all sold through custom quotes rather than published list prices because Greenhouse pricing depends on plan selection, hiring volume, organizational complexity and the specific features a company needs. Core is positioned for companies establishing consistent hiring processes for the first time or replacing manual, spreadsheet-based recruiting tools, and includes sourcing and CRM, structured interviews, scheduling, standard reporting, single sign-on and Greenhouse's Real Talent matching technology. Plus builds on Core for companies adding new teams or office locations and looking to drive operational efficiency, layering in AI-powered report filters, a Business Intelligence Connector for exporting data into external analytics tools, sourcing automation, candidate texting and fraud detection to catch fabricated candidate identities or AI-generated interview responses. Pro is aimed at large, multi-region organizations managing significant hiring complexity and governance requirements, adding unlimited CRM events, enterprise-grade data security controls, audit logs, a developer sandbox environment for testing integrations, and enterprise-level Real Talent capabilities. Because none of the three tiers has a published price, every prospective customer goes through a sales-assisted quote process, and there is no self-serve free trial or free plan. Greenhouse's core competitors include Lever, Workday Recruiting, iCIMS, SmartRecruiters and Ashby, and the company differentiates primarily through its structured-hiring methodology, its deep native integration ecosystem (Greenhouse has one of the largest marketplaces of pre-built recruiting technology integrations in the industry), and its long-standing reputation among high-growth technology companies as the default choice when scaling a recruiting organization from dozens to thousands of hires per year.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '69afcc2a-09a4-49b5-a478-dc5c7b9d0240';

